/**
 * One-off: clear every deterministic-fallback name_correction insight so the
 * "Variant 1 / Variant 2 ..." placeholder rows get regenerated by the
 * auto-generate cron on next access.
 *
 * Background: when the AI call failed, the old fallback path wrote
 * source='deterministic' rows with literal "Variant N" strings. The code is
 * now fixed (apps/web/src/lib/insights/lite/nameCorrection.ts) to derive real
 * spelling variants from the source name even on AI failure, but existing
 * rows still serve the stale placeholder until expiry. This deletes them so
 * users see the corrected output on their next visit.
 *
 * Run: node scripts/clear-stale-name-correction.mjs
 */

import { createClient } from '@supabase/supabase-js';

const SUPABASE_URL = process.env.NEXT_PUBLIC_SUPABASE_URL || process.env.SUPABASE_URL;
const SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY;

if (!SUPABASE_URL || !SERVICE_ROLE_KEY) {
  console.error('Missing required env vars: NEXT_PUBLIC_SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY');
  process.exit(1);
}

const supabase = createClient(SUPABASE_URL, SERVICE_ROLE_KEY, {
  auth: { autoRefreshToken: false, persistSession: false },
});

const { data: stale, error: selErr } = await supabase
  .from('feature_insights')
  .select('id, user_id, generated_at, expires_at')
  .eq('feature_key', 'name_correction')
  .eq('source', 'deterministic');

if (selErr) {
  console.error('select failed', selErr);
  process.exit(1);
}

console.log(`Found ${stale.length} deterministic name_correction rows.`);
if (stale.length === 0) process.exit(0);

const { error: delErr, count } = await supabase
  .from('feature_insights')
  .delete({ count: 'exact' })
  .eq('feature_key', 'name_correction')
  .eq('source', 'deterministic');

if (delErr) {
  console.error('delete failed', delErr);
  process.exit(1);
}

console.log(`Deleted ${count} rows. Next /api/insights/lite/name_correction GET will return 'pending' and the auto-generate cron will repopulate.`);
